import React, { useState, useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { checkPoint, clearPoints, fetchPoints } from '../store/slices/pointsSlice';
import { logout } from '../store/slices/authSlice';
import Graph from './Graph';

function MainPage() {
  const dispatch = useDispatch();
  const { user, token } = useSelector((state) => state.auth);
  const { points, loading, error } = useSelector((state) => state.points);

  // По ТЗ: Checkbox для X и R
  const [selectedX, setSelectedX] = useState([]); // Множественный выбор
  const [y, setY] = useState('');
  const [selectedR, setSelectedR] = useState([]); // Множественный выбор

  // Варианты по ТЗ
  const xOptions = [-5, -4, -3, -2, -1, 0, 1, 2, 3];
  const rOptions = [0, 1, 2, 3, 4, 5]; // По ТЗ, но радиус отрицательным не может быть!

  // Для графика берем первый выбранный R (или 1 по умолчанию)
  const currentR = selectedR.length > 0 ? parseFloat(selectedR[0]) : null;

  const handleXChange = (value) => {
    setSelectedX(prev =>
      prev.includes(value)
        ? prev.filter(v => v !== value)
        : [...prev, value]
    );
  };

  const handleRChange = (value) => {
    setSelectedR(prev =>
      prev.includes(value)
        ? prev.filter(v => v !== value)
        : [value] // Для радиуса обычно один выбор
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (selectedX.length === 0 || !y || selectedR.length === 0) {
      alert('Заполните все поля');
      return;
    }

    const yNum = parseFloat(y);
    if (isNaN(yNum) || yNum < -5 || yNum > 5) {
      alert('Y должен быть числом от -5 до 5');
      return;
    }

    // Проверяем все выбранные X с первым выбранным R
    const rNum = parseFloat(selectedR[0]);
    if (rNum <= 0) {
      alert('Радиус должен быть положительным');
      return;
    }

    // Отправляем все выбранные X
    for (const x of selectedX) {
      dispatch(checkPoint({ x: parseFloat(x), y: yNum, r: rNum }));
    }

    // Очищаем только Y
    setY('');
  };

  const handleCanvasClick = (clickX, clickY) => {
    if (selectedR.length === 0) {
      alert('Сначала выберите радиус R');
      return;
    }

    const rNum = parseFloat(selectedR[0]);
    dispatch(checkPoint({ x: clickX, y: clickY, r: rNum }));
  };

  const handleLogout = () => {
    dispatch(logout());
  };

  const handleClearResults = () => {
    if (window.confirm('Очистить историю проверок?')) {
      dispatch(clearPoints());
    }
  };

  return (
    <div className="main-container">
      <header className="header">
        <div>
          <h1>Проверка попадания точки в область</h1>
          <p>Студент: Ваше ФИО | Группа: PXXXX | Вариант: XXXX</p>
          <p>Пользователь: {user?.username}</p>
        </div>
        <button onClick={handleLogout} className="logout-btn">
          Выйти
        </button>
      </header>

      <div className="content">
        <div className="form-section">
          <form onSubmit={handleSubmit} className="point-form">
            <h2>Введите координаты</h2>

            {/* X: Checkbox группа */}
            <div className="form-group">
              <label>Координата X (checkbox):</label>
              <div className="checkbox-group">
                {xOptions.map(value => (
                  <label key={value} className="checkbox-label">
                    <input
                      type="checkbox"
                      value={value}
                      checked={selectedX.includes(value.toString())}
                      onChange={() => handleXChange(value.toString())}
                    />
                    {value}
                  </label>
                ))}
              </div>
              {selectedX.length > 0 && (
                <small>Выбрано: {selectedX.join(', ')}</small>
              )}
            </div>

            {/* Y: Text input */}
            <div className="form-group">
              <label htmlFor="y">Координата Y (text):</label>
              <input
                type="number"
                id="y"
                value={y}
                onChange={(e) => setY(e.target.value)}
                placeholder="-5 ... 5"
                min="-5"
                max="5"
                step="0.1"
                required
              />
              <small>Диапазон: от -5 до 5</small>
            </div>

            {/* R: Checkbox группа (по ТЗ, но странно для радиуса) */}
            <div className="form-group">
              <label>Радиус R (checkbox):</label>
              <div className="checkbox-group">
                {rOptions.map(value => (
                  <label key={value} className="checkbox-label">
                    <input
                      type="checkbox"
                      value={value}
                      checked={selectedR.includes(value.toString())}
                      onChange={() => handleRChange(value.toString())}
                    />
                    {value}
                  </label>
                ))}
              </div>
              {selectedR.length > 0 && (
                <small>Выбран R: {selectedR.join(', ')}</small>
              )}
              <small style={{color: 'red', display: 'block'}}>
                *По ТЗ checkbox, но радиус не может быть отрицательным!
              </small>
            </div>

            {error && <div className="error-message">{error}</div>}

            <button
              type="submit"
              className="submit-btn"
              disabled={loading || selectedX.length === 0 || !y || selectedR.length === 0}
            >
              {loading ? 'Проверка...' : 'Проверить'}
            </button>
          </form>

          <div className="action-buttons">
            <button
              onClick={handleClearResults}
              className="clear-btn"
              disabled={points.length === 0}
            >
              Очистить историю
            </button>
          </div>
        </div>

        <div className="graph-section">
          <Graph
            results={points}
            currentR={currentR}
            onCanvasClick={handleCanvasClick}
          />

          {/* Таблица результатов */}
          <div className="results-section">
            <h2>История проверок ({points.length})</h2>
            {points.length === 0 ? (
              <p className="no-results">Нет результатов</p>
            ) : (
              <table className="results-table">
                <thead>
                  <tr>
                    <th>X</th>
                    <th>Y</th>
                    <th>R</th>
                    <th>Результат</th>
                    <th>Время</th>
                  </tr>
                </thead>
                <tbody>
                  {points.map((point, index) => (
                    <tr key={index} className={point.hit ? 'hit-row' : 'miss-row'}>
                      <td>{point.x.toFixed(2)}</td>
                      <td>{point.y.toFixed(2)}</td>
                      <td>{point.r}</td>
                      <td>
                        <span className={point.hit ? 'hit' : 'miss'}>
                          {point.hit ? '✓ Попадание' : '✗ Промах'}
                        </span>
                      </td>
                      <td>
                        {point.createdAt ?
                          new Date(point.createdAt).toLocaleTimeString('ru-RU') :
                          '--:--:--'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default MainPage;
